@tailwind base;
@tailwind components;
@tailwind utilities;

/* Fonts */
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&family=JetBrains+Mono:wght@400;500&display=swap');

/* Leaflet Map Styles */
@import 'leaflet/dist/leaflet.css';

:root {
  --canvas: #0A0A0A;
  --panel: #141414;
  --elevated: #1C1C1C;
  --hover: #262626;
  --border: #2A2A2A;
  --text-primary: #FAFAFA;
  --text-secondary: #A1A1A1;
  --text-muted: #6B6B6B;
}

body {
  color: var(--text-primary);
  background-color: var(--canvas);
  font-family: 'Inter', system-ui, sans-serif;
}

/* Railway Domain Typography */
.train-id {
  font-family: 'JetBrains Mono', 'Monaco', 'Menlo', monospace;
  font-weight: 600;
}

.km-value {
  font-family: 'JetBrains Mono', monospace;
  font-variant-numeric: tabular-nums;
}

/* Scrollbar styling for dark mode */
::-webkit-scrollbar {
  width: 8px;
  height: 8px;
}

::-webkit-scrollbar-track {
  background: var(--panel);
}

::-webkit-scrollbar-thumb {
  background: var(--border);
  border-radius: 4px;
}

::-webkit-scrollbar-thumb:hover {
  background: var(--hover);
}

/* Map container dark mode */
.leaflet-container {
  background-color: var(--canvas);
}

/* Custom focus states */
*:focus-visible {
  outline: 2px solid #3b82f6;
  outline-offset: 2px;
}

/** @type {import('tailwindcss').Config} */
module.exports = {
  content: [
    './src/**/*.{js,ts,jsx,tsx,mdx}',
  ],
  theme: {
    extend: {
      colors: {
        // MMS Brand Colors
        primary: {
          50: '#eff6ff',
          100: '#dbeafe',
          200: '#bfdbfe',
          300: '#93c5fd',
          400: '#60a5fa',
          500: '#3b82f6',
          600: '#2563eb',
          700: '#1d4ed8',
          800: '#1e40af',
          900: '#1e3a8a',
        },
        // Status Colors
        status: {
          available: '#22c55e',    // Green
          inService: '#3b82f6',    // Blue
          maintenance: '#ef4444',  // Red
        },
        // Variance Traffic Light
        variance: {
          green: '#22c55e',
          yellow: '#eab308',
          red: '#ef4444',
        },
        // Dark Mode Enterprise Colors
        canvas: '#0A0A0A',
        panel: '#141414',
        elevated: '#1C1C1C',
        hover: '#262626',
        border: '#2A2A2A',
        // Text hierarchy
        'text-primary': '#FAFAFA',
        'text-secondary': '#A1A1A1',
        'text-muted': '#6B6B6B',
        // Maintenance Types
        'maint-pm1': '#10B981',      // Green - Preventive Minor
        'maint-pm2': '#3B82F6',      // Blue - Preventive Major
        'maint-pm3': '#F59E0B',      // Amber - Heavy Maintenance
        'maint-overhaul': '#EF4444', // Red - Overhaul
      },
      fontFamily: {
        sans: ['Inter', 'system-ui', 'sans-serif'],
        mono: ['JetBrains Mono', 'monospace'],
      },
    },
  },
  plugins: [],
};

