     3→import React, { useRef, useEffect, useCallback, useState } from 'react';
     4→import { Application, Container, Graphics, Text, TextStyle } from 'pixi.js';
     5→import { Viewport } from 'pixi-viewport';
     6→import {
     7→  LODLevel,
     8→  getLODFromScale,
     9→} from '@/stores/viewportStore';
    10→
    11→interface MaintenanceEvent {
    12→  id: string;
    13→  trainId: string;
    14→  trainName: string;
    15→  type: 'PM1' | 'PM2' | 'HM' | 'OVH';
    16→  startDate: Date;
    17→  endDate: Date;
    18→  depot: string;
    19→}
    20→
    21→interface ScheduleCanvasProps {
    22→  events: MaintenanceEvent[];
    23→  onEventSelect?: (event: MaintenanceEvent) => void;
    24→  onEventHover?: (event: MaintenanceEvent | null) => void;
    25→  startDate?: Date;
    26→  endDate?: Date;
    27→  width?: number;
    28→  height?: number;
    29→}
    30→
    31→// Color palette for maintenance types
    32→const MAINTENANCE_COLORS = {
    33→  PM1: 0x10B981, // Green
    34→  PM2: 0x3B82F6, // Blue
    35→  HM: 0xF59E0B,  // Amber
    36→  OVH: 0xEF4444, // Red
    37→};
    38→
    39→// LOD level descriptions
    40→const LOD_LABELS = {
    41→  0: 'Strategic (10-12 years)',
    42→  1: 'Tactical (1-3 years)',
    43→  2: 'Operational (1-6 months)',
    44→  3: 'Execution (1-4 weeks)',
    45→};
    46→
    47→// Day width in pixels at scale 1.0
    48→const DAY_WIDTH = 20;
    49→const ROW_HEIGHT = 40;
    50→const HEADER_HEIGHT = 60;
    51→
    52→export function ScheduleCanvas({
    53→  events,
    54→  onEventSelect,
    55→  onEventHover,
    56→  startDate = new Date(),
    57→  endDate = new Date(Date.now() + 365 * 24 * 60 * 60 * 1000),
    58→  width = 1200,
    59→  height = 600,
    60→}: ScheduleCanvasProps) {
    61→  const containerRef = useRef<HTMLDivElement>(null);
    62→  const appRef = useRef<Application | null>(null);
    63→  const viewportRef = useRef<Viewport | null>(null);
    64→
    65→  // Use local state for LOD and scale to avoid toolkit infinite loop issue
    66→  const [currentLOD, setCurrentLOD] = useState<LODLevel>(2);
    67→  const [scale, setScale] = useState(0.5);
    68→
    69→  // Initialize Pixi application
    70→  useEffect(() => {
    71→    if (!containerRef.current) return;
    72→
    73→    const app = new Application();
    74→
    75→    const initApp = async () => {
    76→      await app.init({
    77→        width,
    78→        height,
    79→        backgroundColor: 0x0A0A0A, // Dark canvas background
    80→        resolution: window.devicePixelRatio || 1,
    81→        autoDensity: true,
    82→        antialias: true,
    83→      });
    84→
    85→      containerRef.current?.appendChild(app.canvas);
    86→      appRef.current = app;
    87→
    88→      // Create viewport
    89→      const viewport = new Viewport({
    90→        screenWidth: width,
    91→        screenHeight: height,
    92→        worldWidth: width * 10,
    93→        worldHeight: height * 5,
    94→        events: app.renderer.events,
    95→      });
    96→
    97→      app.stage.addChild(viewport);
    98→      viewportRef.current = viewport;
    99→
   100→      // Enable viewport interactions
   101→      viewport
   102→        .drag()
   103→        .pinch()
   104→        .wheel()
   105→        .decelerate()
   106→        .clampZoom({
   107→          minScale: 0.05,
   108→          maxScale: 4.0,
   109→        });
   110→
   111→      // Listen to zoom/scale changes - update local state
   112→      viewport.on('zoomed', () => {
   113→        const newScale = viewport.scale.x;
   114→        setScale(newScale);
   115→        setCurrentLOD(getLODFromScale(newScale));
   116→      });
   117→
   118→      viewport.on('moved', () => {
   119→        // Position tracking handled by viewport internally
   120→      });
   121→
   122→      // Initial render
   123→      renderContent(viewport, events, startDate, endDate, getLODFromScale(0.5));
   124→    };
   125→
   126→    initApp();
   127→
   128→    return () => {
   129→      if (appRef.current) {
   130→        appRef.current.destroy(true);
   131→        appRef.current = null;
   132→      }
   133→    };
   134→  }, [width, height]);
   135→
   136→  // Re-render when events or LOD changes
   137→  useEffect(() => {
   138→    if (viewportRef.current) {
   139→      renderContent(viewportRef.current, events, startDate, endDate, currentLOD);
   140→    }
   141→  }, [events, currentLOD, startDate, endDate]);
   142→
   143→  // Handle window resize
   144→  useEffect(() => {
   145→    const handleResize = () => {
   146→      if (appRef.current && viewportRef.current) {
   147→        appRef.current.renderer.resize(width, height);
   148→        viewportRef.current.resize(width, height);
   149→      }
   150→    };
   151→
   152→    window.addEventListener('resize', handleResize);
   153→    return () => window.removeEventListener('resize', handleResize);
   154→  }, [width, height]);
   155→
   156→  const renderContent = useCallback(
   157→    (
   158→      viewport: Viewport,
   159→      events: MaintenanceEvent[],
   160→      startDate: Date,
   161→      endDate: Date,
   162→      lod: LODLevel
   163→    ) => {
   164→      // Clear existing children except the viewport container
   165→      viewport.removeChildren();
   166→
   167→      // Create container for all content
   168→      const contentContainer = new Container();
   169→      viewport.addChild(contentContainer);
   170→
   171→      // Render based on LOD level
   172→      switch (lod) {
   173→        case 0:
   174→          renderStrategicView(contentContainer, events, startDate, endDate);
   175→          break;
   176→        case 1:
   177→          renderTacticalView(contentContainer, events, startDate, endDate);
   178→          break;
   179→        case 2:
   180→          renderOperationalView(contentContainer, events, startDate, endDate);
   181→          break;
   182→        case 3:
   183→          renderExecutionView(contentContainer, events, startDate, endDate, onEventSelect, onEventHover);
   184→          break;
   185→      }
   186→
   187→      // Add timeline ruler
   188→      renderTimelineRuler(contentContainer, startDate, endDate, lod);
   189→    },
   190→    [onEventSelect, onEventHover]
   191→  );
   192→
   193→  return (
   194→    <div className="relative">
   195→      {/* Canvas container */}
   196→      <div ref={containerRef} className="rounded-lg overflow-hidden" />
   197→
   198→      {/* Overlay controls */}
   199→      <div className="absolute top-4 left-4 bg-panel/90 backdrop-blur-sm rounded-lg p-3 space-y-2">
   200→        <div className="text-xs text-text-secondary">LOD Level</div>
   201→        <div className="text-sm font-medium text-text-primary">
   202→          {LOD_LABELS[currentLOD as keyof typeof LOD_LABELS]}
   203→        </div>
   204→        <div className="text-xs text-text-muted">
   205→          Scale: {(scale * 100).toFixed(0)}%
   206→        </div>
   207→      </div>
   208→
   209→      {/* Zoom controls */}
   210→      <div className="absolute bottom-4 right-4 flex gap-2">
   211→        <button
   212→          onClick={() => viewportRef.current?.zoomPercent(0.2, true)}
   213→          className="p-2 bg-panel hover:bg-elevated rounded text-text-primary"
   214→        >
   215→          +
   216→        </button>
   217→        <button
   218→          onClick={() => viewportRef.current?.zoomPercent(-0.2, true)}
   219→          className="p-2 bg-panel hover:bg-elevated rounded text-text-primary"
   220→        >
   221→          -
   222→        </button>
   223→        <button
   224→          onClick={() => {
   225→            viewportRef.current?.fit();
   226→            viewportRef.current?.moveCenter(width / 2, height / 2);
   227→          }}
   228→          className="p-2 bg-panel hover:bg-elevated rounded text-text-primary text-xs"
   229→        >
   230→          Fit
   231→        </button>
   232→      </div>
   233→    </div>
   234→  );
   235→}
   236→
   237→// LOD 0: Strategic View (10-12 years) - Heatmap aggregation
   238→function renderStrategicView(
   239→  container: Container,
   240→  events: MaintenanceEvent[],
   241→  startDate: Date,
   242→  endDate: Date
   243→) {
   244→  const graphics = new Graphics();
   245→  container.addChild(graphics);
   246→
   247→  // Calculate yearly aggregations
   248→  const yearlyData = new Map<number, { PM1: number; PM2: number; HM: number; OVH: number }>();
   249→
   250→  events.forEach((event) => {
   251→    const year = event.startDate.getFullYear();
   252→    if (!yearlyData.has(year)) {
   253→      yearlyData.set(year, { PM1: 0, PM2: 0, HM: 0, OVH: 0 });
   254→    }
   255→    const data = yearlyData.get(year)!;
   256→    data[event.type]++;
   257→  });
   258→
   259→  // Render yearly blocks
   260→  const years = Array.from(yearlyData.keys()).sort();
   261→  const blockWidth = 100;
   262→  const blockHeight = 80;
   263→
   264→  years.forEach((year, index) => {
   265→    const data = yearlyData.get(year)!;
   266→    const total = data.PM1 + data.PM2 + data.HM + data.OVH;
   267→    const intensity = Math.min(1, total / 50); // Normalize
   268→
   269→    graphics.rect(
   270→      index * (blockWidth + 10) + 20,
   271→      HEADER_HEIGHT,
   272→      blockWidth,
   273→      blockHeight
   274→    );
   275→    graphics.fill({ color: 0x3B82F6, alpha: 0.3 + intensity * 0.7 });
   276→
   277→    // Year label
   278→    const style = new TextStyle({
   279→      fontSize: 14,
   280→      fill: 0xFAFAFA,
   281→      fontFamily: 'Inter',
   282→    });
   283→    const yearText = new Text({ text: year.toString(), style });
   284→    yearText.x = index * (blockWidth + 10) + 20 + blockWidth / 2 - yearText.width / 2;
   285→    yearText.y = HEADER_HEIGHT + blockHeight + 5;
   286→    container.addChild(yearText);
   287→
   288→    // Count label
   289→    const countStyle = new TextStyle({
   290→      fontSize: 20,
   291→      fill: 0xFAFAFA,
   292→      fontWeight: 'bold',
   293→      fontFamily: 'Inter',
   294→    });
   295→    const countText = new Text({ text: total.toString(), style: countStyle });
   296→    countText.x = index * (blockWidth + 10) + 20 + blockWidth / 2 - countText.width / 2;
   297→    countText.y = HEADER_HEIGHT + blockHeight / 2 - countText.height / 2;
   298→    container.addChild(countText);
   299→  });
   300→}
   301→
   302→// LOD 1: Tactical View (1-3 years) - Campaign bars
   303→function renderTacticalView(
   304→  container: Container,
   305→  events: MaintenanceEvent[],
   306→  startDate: Date,
   307→  endDate: Date
   308→) {
   309→  const graphics = new Graphics();
   310→  container.addChild(graphics);
   311→
   312→  // Calculate quarterly aggregations
   313→  const quarterlyData = new Map<string, { PM1: number; PM2: number; HM: number; OVH: number }>();
   314→
   315→  events.forEach((event) => {
   316→    const year = event.startDate.getFullYear();
   317→    const quarter = Math.floor(event.startDate.getMonth() / 3) + 1;
   318→    const key = `${year}-Q${quarter}`;
   319→
   320→    if (!quarterlyData.has(key)) {
   321→      quarterlyData.set(key, { PM1: 0, PM2: 0, HM: 0, OVH: 0 });
   322→    }
   323→    const data = quarterlyData.get(key)!;
   324→    data[event.type]++;
   325→  });
   326→
   327→  // Render quarterly bars
   328→  const quarters = Array.from(quarterlyData.keys()).sort();
   329→  const barWidth = 60;
   330→  const maxHeight = 150;
   331→
   332→  quarters.forEach((quarter, index) => {
   333→    const data = quarterlyData.get(quarter)!;
   334→    let yOffset = HEADER_HEIGHT;
   335→
   336→    // Stack by type
   337→    (['PM1', 'PM2', 'HM', 'OVH'] as const).forEach((type) => {
   338→      const count = data[type];
   339→      if (count > 0) {
   340→        const height = (count / 20) * maxHeight;
   341→        graphics.rect(
   342→          index * (barWidth + 5) + 20,
   343→          yOffset,
   344→          barWidth,
   345→          height
   346→        );
   347→        graphics.fill({ color: MAINTENANCE_COLORS[type] });
   348→        yOffset += height;
   349→      }
   350→    });
   351→
   352→    // Quarter label
   353→    const style = new TextStyle({
   354→      fontSize: 10,
   355→      fill: 0xA1A1A1,
   356→      fontFamily: 'Inter',
   357→    });
   358→    const text = new Text({ text: quarter, style });
   359→    text.x = index * (barWidth + 5) + 20 + barWidth / 2 - text.width / 2;
   360→    text.y = HEADER_HEIGHT + maxHeight + 5;
   361→    container.addChild(text);
   362→  });
   363→}
   364→
   365→// LOD 2: Operational View (1-6 months) - Work orders as blocks
   366→function renderOperationalView(
   367→  container: Container,
   368→  events: MaintenanceEvent[],
   369→  startDate: Date,
   370→  endDate: Date
   371→) {
   372→  const graphics = new Graphics();
   373→  container.addChild(graphics);
   374→
   375→  // Group by train
   376→  const trainGroups = new Map<string, MaintenanceEvent[]>();
   377→  events.forEach((event) => {
   378→    if (!trainGroups.has(event.trainId)) {
   379→      trainGroups.set(event.trainId, []);
   380→    }
   381→    trainGroups.get(event.trainId)!.push(event);
   382→  });
   383→
   384→  const trains = Array.from(trainGroups.keys()).slice(0, 15); // Limit visible trains
   385→  const startTime = startDate.getTime();
   386→  const msPerDay = 24 * 60 * 60 * 1000;
   387→
   388→  trains.forEach((trainId, rowIndex) => {
   389→    const trainEvents = trainGroups.get(trainId)!;
   390→    const y = HEADER_HEIGHT + rowIndex * ROW_HEIGHT;
   391→
   392→    // Row background
   393→    graphics.rect(0, y, 2000, ROW_HEIGHT - 2);
   394→    graphics.fill({ color: rowIndex % 2 === 0 ? 0x141414 : 0x1C1C1C });
   395→
   396→    // Train label
   397→    const style = new TextStyle({
   398→      fontSize: 11,
   399→      fill: 0xA1A1A1,
   400→      fontFamily: 'JetBrains Mono',
   401→    });
   402→    const label = new Text({ text: trainEvents[0]?.trainName || trainId, style });
   403→    label.x = 10;
   404→    label.y = y + ROW_HEIGHT / 2 - label.height / 2;
   405→    container.addChild(label);
   406→
   407→    // Events
   408→    trainEvents.forEach((event) => {
   409→      const startOffset = (event.startDate.getTime() - startTime) / msPerDay;
   410→      const duration = (event.endDate.getTime() - event.startDate.getTime()) / msPerDay;
   411→
   412→      const x = 120 + startOffset * DAY_WIDTH;
   413→      const width = Math.max(duration * DAY_WIDTH, 8);
   414→
   415→      graphics.rect(x, y + 4, width, ROW_HEIGHT - 8);
   416→      graphics.fill({ color: MAINTENANCE_COLORS[event.type] });
   417→    });
   418→  });
   419→}
   420→
   421→// LOD 3: Execution View (1-4 weeks) - Full task details
   422→function renderExecutionView(
   423→  container: Container,
   424→  events: MaintenanceEvent[],
   425→  startDate: Date,
   426→  endDate: Date,
   427→  onEventSelect?: (event: MaintenanceEvent) => void,
   428→  onEventHover?: (event: MaintenanceEvent | null) => void
   429→) {
   430→  const graphics = new Graphics();
   431→  container.addChild(graphics);
   432→
   433→  // Group by train
   434→  const trainGroups = new Map<string, MaintenanceEvent[]>();
   435→  events.forEach((event) => {
   436→    if (!trainGroups.has(event.trainId)) {
   437→      trainGroups.set(event.trainId, []);
   438→    }
   439→    trainGroups.get(event.trainId)!.push(event);
   440→  });
   441→
   442→  const trains = Array.from(trainGroups.keys()).slice(0, 20);
   443→  const startTime = startDate.getTime();
   444→  const msPerDay = 24 * 60 * 60 * 1000;
   445→
   446→  trains.forEach((trainId, rowIndex) => {
   447→    const trainEvents = trainGroups.get(trainId)!;
   448→    const y = HEADER_HEIGHT + rowIndex * ROW_HEIGHT;
   449→
   450→    // Row background
   451→    graphics.rect(0, y, 3000, ROW_HEIGHT - 2);
   452→    graphics.fill({ color: rowIndex % 2 === 0 ? 0x141414 : 0x1C1C1C });
   453→
   454→    // Train label
   455→    const style = new TextStyle({
   456→      fontSize: 12,
   457→      fill: 0xFAFAFA,
   458→      fontFamily: 'JetBrains Mono',
   459→    });
   460→    const label = new Text({ text: trainEvents[0]?.trainName || trainId, style });
   461→    label.x = 10;
   462→    label.y = y + ROW_HEIGHT / 2 - label.height / 2;
   463→    container.addChild(label);
   464→
   465→    // Events with full details
   466→    trainEvents.forEach((event) => {
   467→      const startOffset = (event.startDate.getTime() - startTime) / msPerDay;
   468→      const duration = (event.endDate.getTime() - event.startDate.getTime()) / msPerDay;
   469→
   470→      const x = 150 + startOffset * DAY_WIDTH * 2; // Larger scale at execution level
   471→      const width = Math.max(duration * DAY_WIDTH * 2, 30);
   472→
   473→      // Event block
   474→      const eventGraphics = new Graphics();
   475→      eventGraphics.rect(0, 0, width, ROW_HEIGHT - 10);
   476→      eventGraphics.fill({ color: MAINTENANCE_COLORS[event.type] });
   477→
   478→      // Rounded corners simulation
   479→      eventGraphics.rect(0, 0, width, ROW_HEIGHT - 10);
   480→      eventGraphics.fill({ color: MAINTENANCE_COLORS[event.type] });
   481→
   482→      eventGraphics.x = x;
   483→      eventGraphics.y = y + 5;
   484→      eventGraphics.eventMode = 'static';
   485→      eventGraphics.cursor = 'pointer';
   486→
   487→      eventGraphics.on('pointerover', () => {
   488→        eventGraphics.alpha = 0.8;
   489→        onEventHover?.(event);
   490→      });
   491→
   492→      eventGraphics.on('pointerout', () => {
   493→        eventGraphics.alpha = 1;
   494→        onEventHover?.(null);
   495→      });
   496→
   497→      eventGraphics.on('pointertap', () => {
   498→        onEventSelect?.(event);
   499→      });
   500→
   501→      container.addChild(eventGraphics);
   502→
   503→      // Event type label
   504→      if (width > 40) {
   505→        const typeStyle = new TextStyle({
   506→          fontSize: 10,
   507→          fill: 0xFFFFFF,
   508→          fontWeight: 'bold',
   509→          fontFamily: 'Inter',
   510→        });
   511→        const typeText = new Text({ text: event.type, style: typeStyle });
   512→        typeText.x = x + 5;
   513→        typeText.y = y + 8;
   514→        container.addChild(typeText);
   515→
   516→        // Depot label
   517→        if (width > 80) {
   518→          const depotStyle = new TextStyle({
   519→            fontSize: 9,
   520→            fill: 0xCCCCCC, // Lighter color instead of alpha
   521→            fontFamily: 'Inter',
   522→          });
   523→          const depotText = new Text({ text: event.depot, style: depotStyle });
   524→          depotText.x = x + 5;
   525→          depotText.y = y + 22;
   526→          container.addChild(depotText);
   527→        }
   528→      }
   529→    });
   530→  });
   531→}
   532→
   533→// Timeline ruler
   534→function renderTimelineRuler(
   535→  container: Container,
   536→  startDate: Date,
   537→  endDate: Date,
   538→  lod: LODLevel
   539→) {
   540→  const graphics = new Graphics();
   541→  container.addChild(graphics);
   542→
   543→  // Header background
   544→  graphics.rect(0, 0, 3000, HEADER_HEIGHT);
   545→  graphics.fill({ color: 0x1C1C1C });
   546→
   547→  const style = new TextStyle({
   548→    fontSize: 11,
   549→    fill: 0xA1A1A1,
   550→    fontFamily: 'Inter',
   551→  });
   552→
   553→  // Different granularity based on LOD
   554→  const msPerDay = 24 * 60 * 60 * 1000;
   555→  const startTime = startDate.getTime();
   556→
   557→  if (lod >= 2) {
   558→    // Show months
   559→    const months = [];
   560→    let current = new Date(startDate);
   561→    while (current < endDate) {
   562→      months.push(new Date(current));
   563→      current.setMonth(current.getMonth() + 1);
   564→    }
   565→
   566→    months.forEach((month, index) => {
   567→      const offset = (month.getTime() - startTime) / msPerDay;
   568→      const x = 150 + offset * DAY_WIDTH * (lod === 3 ? 2 : 1);
   569→
   570→      // Month line
   571→      graphics.moveTo(x, HEADER_HEIGHT - 20);
   572→      graphics.lineTo(x, HEADER_HEIGHT);
   573→      graphics.stroke({ color: 0x2A2A2A, width: 1 });
   574→
   575→      // Month label
   576→      const monthLabel = month.toLocaleDateString('en-US', {
   577→        month: 'short',
   578→        year: '2-digit',
   579→      });
   580→      const text = new Text({ text: monthLabel, style });
   581→      text.x = x + 5;
   582→      text.y = HEADER_HEIGHT - 18;
   583→      container.addChild(text);
   584→    });
   585→  }
   586→}
   587→
   588→export default ScheduleCanvas;
