     1→/**
     2→ * MMS - Viewport Store for Semantic Zoom Canvas
     3→ *
     4→ * State management using @zazcart/toolkit
     5→ * Manages zoom level, pan position, LOD (Level of Detail), and selection
     6→ */
     7→
     8→import { createSlice, createMachine, createMachineConfig } from '@zazcart/toolkit';
     9→
    10→// LOD Level definitions
    11→export type LODLevel = 0 | 1 | 2 | 3;
    12→
    13→export const LOD_THRESHOLDS = {
    14→  STRATEGIC: { min: 0.05, max: 0.2 },   // LOD 0: 10-12 years
    15→  TACTICAL: { min: 0.2, max: 0.5 },      // LOD 1: 1-3 years
    16→  OPERATIONAL: { min: 0.5, max: 1.0 },   // LOD 2: 1-6 months
    17→  EXECUTION: { min: 1.0, max: 4.0 },     // LOD 3: 1-4 weeks
    18→} as const;
    19→
    20→// Determine LOD level from scale
    21→export function getLODFromScale(scale: number): LODLevel {
    22→  if (scale < LOD_THRESHOLDS.TACTICAL.min) return 0;
    23→  if (scale < LOD_THRESHOLDS.OPERATIONAL.min) return 1;
    24→  if (scale < LOD_THRESHOLDS.EXECUTION.min) return 2;
    25→  return 3;
    26→}
    27→
    28→// Create the viewport slice with inline initial state (pattern from toolkit tests)
    29→const viewportSlice = createSlice({
    30→  id: 'viewport',
    31→  cache: { policy: 'private' as const },
    32→  initial: {
    33→    scale: 0.5,
    34→    translateX: 0,
    35→    translateY: 0,
    36→    currentLOD: 2 as LODLevel,
    37→    visibleStartDate: new Date().toISOString(),
    38→    visibleEndDate: new Date(Date.now() + 180 * 24 * 60 * 60 * 1000).toISOString(),
    39→    isZooming: false,
    40→    isPanning: false,
    41→    selectedItems: [] as string[],
    42→    hoveredItem: null as string | null,
