/**
 * MMS - Viewport Store for Semantic Zoom Canvas
 *
 * State management using @zazcart/toolkit
 * Manages zoom level, pan position, LOD (Level of Detail), and selection
 */

import { createSlice, createMachine, createMachineConfig } from '@zazcart/toolkit';

// LOD Level definitions
export type LODLevel = 0 | 1 | 2 | 3;

export const LOD_THRESHOLDS = {
  STRATEGIC: { min: 0.05, max: 0.2 },   // LOD 0: 10-12 years
  TACTICAL: { min: 0.2, max: 0.5 },      // LOD 1: 1-3 years
  OPERATIONAL: { min: 0.5, max: 1.0 },   // LOD 2: 1-6 months
  EXECUTION: { min: 1.0, max: 4.0 },     // LOD 3: 1-4 weeks
} as const;

// Determine LOD level from scale
export function getLODFromScale(scale: number): LODLevel {
  if (scale < LOD_THRESHOLDS.TACTICAL.min) return 0;
  if (scale < LOD_THRESHOLDS.OPERATIONAL.min) return 1;
  if (scale < LOD_THRESHOLDS.EXECUTION.min) return 2;
  return 3;
}

// Create the viewport slice with inline initial state (pattern from toolkit tests)
const viewportSlice = createSlice({
  id: 'viewport',
  cache: { policy: 'private' as const },
  initial: {
    scale: 0.5,
    translateX: 0,
    translateY: 0,
    currentLOD: 2 as LODLevel,
    visibleStartDate: new Date().toISOString(),
    visibleEndDate: new Date(Date.now() + 180 * 24 * 60 * 60 * 1000).toISOString(),
    isZooming: false,
    isPanning: false,
    selectedItems: [] as string[],
    hoveredItem: null as string | null,
  },
  reducers: {
    zoom: (state, payload: { scale: number }) => {
      const newScale = Math.max(0.05, Math.min(4.0, payload.scale));
      state.scale = newScale;
      state.currentLOD = getLODFromScale(newScale);
      state.isZooming = true;
    },

    zoomEnd: state => {
      state.isZooming = false;
    },

    pan: (state, payload: { deltaX: number; deltaY: number }) => {
      state.translateX += payload.deltaX;
      state.translateY += payload.deltaY;
      state.isPanning = true;
    },

    panEnd: state => {
      state.isPanning = false;
    },

    setPosition: (state, payload: { x: number; y: number }) => {
      state.translateX = payload.x;
      state.translateY = payload.y;
    },

    selectItem: (state, payload: { itemId: string; additive?: boolean }) => {
      if (!payload.additive) {
        state.selectedItems = [payload.itemId];
      } else if (!state.selectedItems.includes(payload.itemId)) {
        state.selectedItems.push(payload.itemId);
      }
    },

    deselectItem: (state, payload: { itemId: string }) => {
      state.selectedItems = state.selectedItems.filter((id: string) => id !== payload.itemId);
    },

    clearSelection: state => {
      state.selectedItems = [];
    },

    hoverItem: (state, payload: { itemId: string | null }) => {
      state.hoveredItem = payload.itemId;
    },

    setVisibleRange: (state, payload: { startDate: string; endDate: string }) => {
      state.visibleStartDate = payload.startDate;
      state.visibleEndDate = payload.endDate;
    },

    reset: state => {
      state.scale = 0.5;
      state.translateX = 0;
      state.translateY = 0;
      state.currentLOD = 2;
      state.isZooming = false;
      state.isPanning = false;
      state.selectedItems = [];
      state.hoveredItem = null;
    },
  },
});

// Create the machine config
const viewportMachineConfig = createMachineConfig({
  id: 'viewportMachine',
  slices: {
    viewport: viewportSlice,
  },
  selectors: {
    lodLabel: state => {
      const labels: Record<number, string> = {
        0: 'Strategic (10-12 years)',
        1: 'Tactical (1-3 years)',
        2: 'Operational (1-6 months)',
        3: 'Execution (1-4 weeks)',
      };
      return labels[state.viewport.currentLOD] || 'Unknown';
    },
    scalePercent: state => Math.round(state.viewport.scale * 100),
    hasSelection: state => state.viewport.selectedItems.length > 0,
    selectionCount: state => state.viewport.selectedItems.length,
  },
});

// Create the machine
export const viewportMachine = createMachine(viewportMachineConfig);

// Export actions for convenience
export const viewportActions = viewportMachine.actions.viewport;

// Export action types for external use
export const viewportActionTypes = viewportMachine.actionTypes.viewport;

// Helper to get current state
export function getViewportState() {
  return viewportMachine.getState().viewport;
}

// Export the useMachine hook for React components
export const useViewport = viewportMachine.useMachine;
export const useViewportSelector = viewportMachine.useSelector;
